#include <stdio.h>

void bad_printf_examples() {
    printf("%d", 1.2);           // Noncompliant: double passed for %d
    printf("%d %d", 1);         // Noncompliant: missing second argument
    printf("%s", 42);           // Noncompliant: int passed for %s
    printf("%f", "hello");      // Noncompliant: string passed for %f
}

#include <stdio.h>

void more_bad_examples() {
    char* str = NULL;
    printf("%s", str);          // Noncompliant: NULL pointer
    printf("%ld", 100);         // Noncompliant: int passed for %ld
    printf("%c %c", 'a');       // Noncompliant: missing second character
}

compliant:
#include <stdio.h>

void good_printf_examples() {
    printf("%d", 42);           // Compliant: int for %d
    printf("%d %d", 1, 2);      // Compliant: correct number of args
    printf("%s", "hello");      // Compliant: string for %s
    printf("%f", 3.14);         // Compliant: double for %f
    printf("%ld", 100L);        // Compliant: long for %ld
}

#include <stdio.h>

void safe_printf_examples() {
    char* str = "valid string";
    printf("%s", str);          // Compliant: valid string pointer
    printf("%c %c", 'a', 'b');   // Compliant: correct number of chars

    // Using proper format specifiers
    int value = 10;
    printf("Value: %d\n", value);  // Compliant
}
